export default {
  async search(email) {
    const {
      data,
      error
    } = await this.fetchCustomers(email);
    if (error) throw error;
    return data || [];
  },
  async getByEmail(email) {
    const {
      data,
      error
    } = await this.fetchCustomerByEmail(email);
    if (error) throw error;
    return data;
  },
  async create(customer) {
    const {
      data,
      error
    } = await this.createCustomer(customer);
    if (error) throw error;
    return data;
  },
  async createOrUpdate(customer) {
    const existing = await this.getByEmail(customer.email);
    if (existing) {
      const {
        data,
        error
      } = await this.updateCustomer(customer).eq('email', customer.email).select().single();
      if (error) throw error;
      return data;
    } else {
      return await this.create(customer);
    }
  }
};
